fun greet(name: String?) {
    // Safe call + Elvis operator
    val length = name?.length ?: 0
    println("Length is $length")

    // Smart-cast after a null check
    if (name != null) {
        println(name.uppercase())
    }
}

greet(null)      // Length is 0
greet("Kotlin") // Length is 6, KOTLIN

sealed class Result<out T>
data class Success<T>(val data: T) : Result<T>()
data class Error(val message: String) : Result<Nothing>()
object Loading : Result<Nothing>()

fun <T> render(state: Result<T>): String = when (state) {
    is Success -> "Data: ${state.data}"
    is Error   -> "Failed: ${state.message}"
    Loading    -> "Loading..."
    // No else needed: compiler knows all cases
}

fun classify(x: Any): String = when (x) {
    0, 1 -> "binary digit"
    in 2..9 -> "single digit"
    is String -> "string of length ${x.length}"
    else -> "something else"
}

// when without a subject acts like an if/else-if chain
fun sign(n: Int) = when {
    n > 0 -> "positive"
    n < 0 -> "negative"
    else -> "zero"
}

fun String.isPalindrome(): Boolean {
    val clean = this.lowercase().filter { it.isLetter() }
    return clean == clean.reversed()
}

println("Racecar".isPalindrome())     // true
println("Kotlin".isPalindrome())      // false

