import kotlinx.coroutines.*

suspend fun loadData() = coroutineScope {
    val users = async { fetchUsers() }   // child 1
    val orders = async { fetchOrders() } // child 2
    // scope waits for both; cancels both if one fails
    users.await() + orders.await()
}

suspend fun fetchUsers(): Int { delay(100); return 3 }
suspend fun fetchOrders(): Int { delay(100); return 5 }

import kotlinx.coroutines.*

suspend fun fetchToken(): String {
    delay(200) // suspends without blocking the thread
    return "abc123"
}

fun main() = runBlocking {
    // runBlocking bridges the blocking world into a coroutine
    val token = fetchToken()
    println("Token: $token")
}

import kotlinx.coroutines.*
import kotlinx.coroutines.flow.*

fun tickerFlow(): Flow<Int> = flow {
    for (i in 1..3) {
        delay(100)
        emit(i) // produces a value
    }
}

fun main() = runBlocking {
    tickerFlow()
        .map { it * 10 }
        .collect { println(it) } // 10, 20, 30
}

