// Anonymous object implementing an interface
val comparator = object : Comparator<Int> {
    override fun compare(a: Int, b: Int) = b - a
}
println(listOf(3, 1, 2).sortedWith(comparator)) // [3, 2, 1]

interface Repository { fun load(): String }
class RealRepo : Repository { override fun load() = "data" }

// Class delegation: CachingRepo forwards to RealRepo
class CachingRepo(repo: Repository) : Repository by repo

// Delegated property: lazy initialization
val config: String by lazy {
    println("computing once")
    "loaded"
}

fun main() {
    println(CachingRepo(RealRepo()).load()) // data
    println(config); println(config)        // computes once
}

inline fun <reified T> Any.asOrNull(): T? =
    if (this is T) this else null

inline fun measure(block: () -> Unit): Long {
    val start = System.nanoTime()
    block() // inlined, no lambda object created
    return System.nanoTime() - start
}

val nanos = measure { (1..1000).sum() }
val text: String? = (42 as Any).asOrNull<String>() // null

interface Producer<out T> { fun produce(): T }
interface Consumer<in T> { fun consume(item: T) }

open class Animal
class Cat : Animal()

val catProducer: Producer<Cat> = object : Producer<Cat> {
    override fun produce() = Cat()
}
val animalProducer: Producer<Animal> = catProducer // OK: covariant

val animalConsumer: Consumer<Animal> = object : Consumer<Animal> {
    override fun consume(item: Animal) {}
}
val catConsumer: Consumer<Cat> = animalConsumer // OK: contravariant

fun describe(value: Any): String {
    if (value is String) {
        // Smart-cast to String here
        return "String of length ${value.length}"
    }
    return "Not a string"
}

class Box(val content: String?) {
