}

val numbers = (1..1_000_000)

// Eager: builds an intermediate list after map
val eager = numbers.map { it * 2 }.filter { it % 3 == 0 }.first()

// Lazy: processes elements one at a time, stops at first match
val lazy = numbers.asSequence()
    .map { it * 2 }
    .filter { it % 3 == 0 }
    .first()

println(lazy) // 6

